import React, { useState } from 'react'
import { setUserRequestPendingStatus } from '@fs/zion-relationship-service'
import { TreeViewRelationship } from '@fs/zion-icon'
import { ListItem } from '@fs/zion-ui'
import { useTranslation } from 'react-i18next'
import { relationshipStatusOptions } from '../useRelationshipReducer'

async function attemptSendRequestNotification({ dispatchStatusCallback, contact, setContactOptInStatusTempCache }) {
  const { cisId, cpUserId } = contact

  const requestSent = await setUserRequestPendingStatus({ cisId, cpUserId, sendNotification: true })

  if (requestSent) setContactOptInStatusTempCache({ cisId, cpUserId }, { isOptedIn: false, isPending: true })
  dispatchStatusCallback(
    requestSent ? relationshipStatusOptions.contactOptOutAndPending : relationshipStatusOptions.contactOptOut
  )
}

export default function ContactOptedOutView({
  setShowStatusParams,
  dispatchRelationshipViewingStatus,
  contact,
  track,
  setContactOptInStatusTempCache,
}) {
  const { t } = useTranslation()
  const [disableActions, setDisableActions] = useState()

  function attemptRequestOptIn(event) {
    setDisableActions(true)
    track('requestViewRelationship:clicked', event?.target)

    attemptSendRequestNotification({ dispatchStatusCallback: callBack, contact, setContactOptInStatusTempCache })

    function callBack(newStatusString) {
      dispatchRelationshipViewingStatus(newStatusString)

      if (newStatusString === relationshipStatusOptions.contactOptOutAndPending)
        setShowStatusParams({
          message: t('relation-view.requested', 'Request sent'),
          type: 'success',
        })

      if (newStatusString === relationshipStatusOptions.contactOptOut) {
        setShowStatusParams({
          message: t('relation-view.request.error', 'Request failed'),
          actionLabel: t('relation-view.retry!', 'TRY AGAIN'),
          actionCallback: attemptRequestOptIn,
          type: 'error',
        })

        setDisableActions(false)
      }
    }
  }

  return (
    <ListItem
      primaryText={t('relation-view.request', 'Request to View Relationship')}
      onClick={attemptRequestOptIn}
      disabled={disableActions}
      startElement={<ListItem.Icon Icon={TreeViewRelationship} />}
    />
  )
}
